import tkinter as tk
from tkinter import messagebox

def is_prime(n):
    if n <= 1:
        return False
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

for num in range(101):
    if is_prime(num):
        print(num)

